    "fields": {"type": "array", "items": {"type": "string"}, "description": "Specific fields to read"}
  },
  "required": ["model", "res_id"]
}

{
  "type": "object",
  "properties": {
    "model": {"type": "string", "description": "Technical model name (e.g. \"sale.order\")"},
